import type { FlagTypes } from './types';

export type { FlagTypes };

// Map non-ISO country ids (e.g. `uk`) to ISO 3166-1 alpha-2 for asset lookup.
// Downstream apps may persist the original id, so translate only at render time.
export const COUNTRY_ID_ALIASES: Record<string, string> = {
  uk: 'gb',
};

export function aliasCountryId(id: string): FlagTypes {
  const lower = id.toLowerCase();
  const aliased = COUNTRY_ID_ALIASES[lower] ?? lower;
  return aliased.toUpperCase() as FlagTypes;
}

export interface FlagIconProps {
  // `string & {}` keeps autocomplete for known FlagTypes while still accepting
  // raw country ids (e.g. `'uk'`) that get aliased internally. Plain
  // `FlagTypes | string` would collapse to `string` and lose the closed-set check.
  flag: FlagTypes | (string & {});
}

export const FlagIcon = ({ flag }: FlagIconProps) => {
  const code = aliasCountryId(flag);
  return (
    <img
      src={`https://www.untitledui.com/images/flags/${code}.svg`}
      className="size-4 max-w-none rounded-full"
      alt={`${code} flag`}
    />
  );
};
